CREATE DATABASE IF NOT EXISTS jpa_radiology;
USE jpa_radiology;

SET FOREIGN_KEY_CHECKS = 0;

DROP TABLE IF EXISTS reservation;
DROP TABLE IF EXISTS r_reservations;
DROP TABLE IF EXISTS r_reservation;
DROP TABLE IF EXISTS p_patients;
DROP TABLE IF EXISTS p_patient;
DROP TABLE IF EXISTS d_devices;

SET FOREIGN_KEY_CHECKS = 1;

-- 1. Eltern: d_devices
CREATE TABLE d_devices
(
    d_id       INT AUTO_INCREMENT PRIMARY KEY,
    d_type     VARCHAR(255) NULL,
    d_location VARCHAR(255) NULL
);

-- 2. Eltern: p_patient
CREATE TABLE p_patient
(
    p_id      INT AUTO_INCREMENT PRIMARY KEY,
    p_name    VARCHAR(255) NULL,
    p_birth   DATE         NULL,
    p_ssn     INT(10)      NULL,
    p_surname VARCHAR(255) NULL,
    p_gender  CHAR         NULL,
    birth     DATE         NULL,
    gender    VARCHAR(1)   NOT NULL,
    name      VARCHAR(255) NULL,
    ssn       BIGINT       NOT NULL,
    surname   VARCHAR(255) NULL
);

-- 3. Eltern: p_patients
CREATE TABLE p_patients
(
    id      INT AUTO_INCREMENT PRIMARY KEY,
    birth   DATE         NULL,
    gender  VARCHAR(1)   NOT NULL,
    name    VARCHAR(255) NULL,
    ssn     BIGINT       NOT NULL,
    surname VARCHAR(255) NULL
);

-- 4. Kind: r_reservation
CREATE TABLE r_reservation
(
    r_id         INT AUTO_INCREMENT PRIMARY KEY,
    r_startTime  DATETIME     NULL,
    r_endTime    DATETIME     NULL,
    r_bodyRegion VARCHAR(255) NULL,
    r_comment    VARCHAR(255) NULL,
    r_p_id       INT          NULL,
    r_d_id       INT          NULL,
    CONSTRAINT r_d_fk FOREIGN KEY (r_d_id) REFERENCES d_devices (d_id),
    CONSTRAINT r_p_fk FOREIGN KEY (r_p_id) REFERENCES p_patient (p_id)
);

-- 5. Kind: r_reservations
CREATE TABLE r_reservations
(
    id          INT AUTO_INCREMENT PRIMARY KEY,
    body_region VARCHAR(255) NULL,
    comment     VARCHAR(255) NULL,
    end_time    DATETIME(6)  NULL,
    start_time  DATETIME(6)  NULL,
    r_d_id      INT          NULL,
    r_p_id      INT          NULL,
    CONSTRAINT FK41xevwoknbeyy16824t0iltlc FOREIGN KEY (r_p_id) REFERENCES p_patients (id),
    CONSTRAINT FK3ipr8u4tso4exs9ox6ej0dfgm FOREIGN KEY (r_p_id) REFERENCES p_patient (p_id),
    CONSTRAINT FKalfc7ka3lk817hc44txqe8i38 FOREIGN KEY (r_d_id) REFERENCES d_devices (d_id)
);

-- 6. Kind: reservation
CREATE TABLE reservation
(
    id          INT AUTO_INCREMENT PRIMARY KEY,
    body_region VARCHAR(255) NULL,
    comment     VARCHAR(255) NULL,
    end_time    DATETIME(6)  NULL,
    start_time  DATETIME(6)  NULL,
    r_d_id      INT          NULL,
    r_p_id      INT          NULL,
    CONSTRAINT FKhx8gip6s8x0tw7xkntgaqcwd2 FOREIGN KEY (r_p_id) REFERENCES p_patients (id)
);

